```rust
use std::collections::{HashMap, LinkedList};
use std::sync::{Arc, Mutex};

pub struct LRUCache<K, V> {
    capacity: usize,
    cache: Arc<Mutex<HashMap<K, (usize, LinkedList<V>)>>>,
}

impl<K, V> LRUCache<K, V> {
    pub fn new(capacity: usize) -> Self {
        LRUCache {
            capacity,
            cache: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn insert(&self, key: K, value: V) {
        let mut cache = self.cache.lock().unwrap();
        if cache.contains_key(&key) {
            cache.insert(key, (1, LinkedList::new()));
        } else if cache.len() >= self.capacity {
            let (oldest_key, _) = cache.iter().next().unwrap().clone();
            cache.remove(&oldest_key);
        }
        let mut list = cache.get_mut(&key).unwrap().1;
        list.push_back(value);
        cache.insert(key, (list.len(), list));
    }

    pub fn get(&self, key: &K) -> Option<&V> {
        let cache = self.cache.lock().unwrap();
        if let Some((_, list)) = cache.get(key) {
            let value = list.back().unwrap();
            let mut list = list;
            list.pop_back();
            cache.insert(key.clone(), (list.len(), list));
            Some(value)
        } else {
            None
        }
    }

    pub fn evict(&self) -> Option<(K, V)> {
        let cache = self.cache.lock().unwrap();
        if let Some((key, _)) = cache.iter().next() {
            cache.remove(key);
            return Some((*key, V::default()));
        }
        None
    }
}
