use rand::RngCore;
use rand_xorshift::XorShiftRng;

pub struct XorshiftRng64 {
    state: u64,
}

impl XorshiftRng64 {
    pub fn new(seed: u64) -> Self {
        Self { state: seed }
    }

    pub fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_mul(0x9d2c5680d18d31a1);
        self.state = self.state ^ (self.state >> 12);
        self.state = self.state ^ (self.state << 25);
        self.state = self.state ^ (self.state >> 27);
        self.state
    }
}

impl RngCore for XorshiftRng64 {
    fn next_u32(&mut self) -> u32 {
        (self.next_u64() & 0xffffffff) as u32
    }

    fn next_u64(&mut self) -> u64 {
        self.next_u64()
    }

    fn fill_bytes(&mut self, dest: &mut [u8]) {
        for i in dest {
            *i = self.next_u32() as u8;
        }
    }

    fn try_fill_bytes(&mut self, dest: &mut [u8]) -> Result<(), rand::Error> {
        self.fill_bytes(dest);
        Ok(())
    }
