use swc_ecma_ast::*;
use swc_ecma_transforms::macros::declare_transform;
use swc_ecma_visit::{Visit, VisitMut};
use swc_ecma_parser::{Syntax, Parser};
use anyhow::{Result, Context};

declare_transform!(simple_log_transform);

struct SimpleLogTransform;

impl VisitMut for SimpleLogTransform {
    fn visit_mut_fn(&mut self, fn_expr: &mut FnExpr) {
        let new_expr = Expr::call(
            Expr::ident(SyntaxToken {
                span: fn_expr.span,
                kind: IdentKind::Name("console".to_string()),
            }),
            vec![Expr::kw(SyntaxToken {
                span: fn_expr.span,
                kind: KeywordKind::Log,
            })],
            fn_expr.span,
        );
        fn_expr.expr = Some(new_expr);
        fn_expr.args.push(Expr::ident(SyntaxToken {
            span: fn_expr.span,
            kind: IdentKind::Name("log".to_string()),
        }));
        fn_expr.span = fn_expr.span.with_attr(SyntaxAttr {
            kind: SyntaxAttrKind::Common,
            key: "simple-log".to_string(),
        });
    }
}

#[derive(StructOpt)]
struct Opt {
    #[structopt(short, long)]
    input: String,

    #[structopt(short, long)]
    output: String,
}

fn main() -> Result<()> {
    let opt = Opt::from_args();

    let source = std::fs::read_to_string(&opt.input)?;
    let parser = Parser::new(Syntax::Es(EsVersion::Es2021), &source);
    let program = parser.parse();

    let mut transform = SimpleLogTransform;
    transform.visit_mut(program)?;

    let printer = Printer::new();
    let output = printer.print(program)?;

    std::fs::write(&opt.output, output)?;

    Ok(())
}
