use notify::{Watcher, RecursiveMode, DebouncedEvent};
use futures::{StreamExt, FutureExt};
use tokio::time::{sleep, Duration};
use tokio_util::sync::CancellationToken;
use async_trait::async_trait;
use slog::{Logger, info};
use slog::{o, Drain, EnvLogger};

const DEBOUNCE_DELAY: Duration = Duration::from_millis(500);

struct Debouncer {
    watcher: Watcher,
    token: CancellationToken,
    delay: Duration,
    logger: Logger,
}

impl Debouncer {
    async fn new(path: &str, delay: Duration, logger: Logger) -> Self {
        let watcher = Watcher::new(move |res| {
            if let Ok(event) = res {
                info!(logger, "Event caught: {:?}", event);
                DebouncedEvent::FileCreated(event.path.clone());
            }
        })
        .unwrap();
        let mut token = CancellationToken::new();
        watcher.watch(path, RecursiveMode::Recursive).unwrap();
        Self {
            watcher,
            token,
            delay,
            logger,
        }
    }

    async fn run(self) {
        let debounced_stream = self.watcher.debounce(DEBOUNCE_DELAY);
        while let Some(event) = debounced_stream.next().await {
            if let DebouncedEvent::FileCreated(path) = event {
                self.callback(path).await;
            }
        }
    }

    async fn callback(&self, path: String) {
        // handle batched event here
        info!(self.logger, "Batched event handled: {}", path);
    }
}

#[tokio::main]
async fn main() {
    let logger = EnvLogger::new(std::env::var("RUST_LOG").unwrap_or_else(|_| "info".to_string()))
        .build()
        .unwrap();
    let debouncer = Debouncer::new("/path/to/watch", DEBOUNCE_DELAY, logger.clone()).await;
    tokio::spawn(debouncer.run());
    tokio::select! {
        _ = tokio::time::sleep(std::time::Duration::from_secs(100)) => {
            // exit after 100 seconds
        }
        _ = debouncer.token.cancelled() => {
            // exit on cancellation
        }
    }
}
