use notify::{Watcher, RecursiveMode, DebouncedEvent};
use std::time::Duration;
use std::thread;
use std::sync::{Arc, Mutex};

struct Debouncer {
    delay: Duration,
    watcher: Watcher,
    events: Arc<Mutex<Vec<DebouncedEvent>>>,
}

impl Debouncer {
    fn new(delay: Duration) -> Self {
        let events = Arc::new(Mutex::new(Vec::new()));
        let watcher = Watcher::new(move |res| {
            let mut events = events.lock().unwrap();
            match res {
                Ok(events) => events.extend(events),
                Err(e) => eprintln!("watch error: {:?}", e),
            }
        }).unwrap();
        watcher.run(move |events| {
            let mut events = events.lock().unwrap();
            while let Some(event) = events.pop() {
                thread::sleep(delay);
                // Process event
                println!("Debounced event: {:?}", event);
            }
        }).unwrap();
        Debouncer { delay, watcher, events }
    }

    fn watch(&self, path: &str, recursive: bool) {
        self.watcher.watch(path, RecursiveMode::recursive).unwrap();
    }
}

fn main() {
    let debouncer = Debouncer::new(Duration::from_millis(500));
    debouncer.watch("/path/to/watch", true);
}
