fn run_script(config_path: String, script_name: String) {
    let config = load_config(config_path);
    let script = config.get("scripts").and_then(|scripts| scripts.get(script_name.as_str()));
    if let Some(script) = script {
        let script_path = Path::new(&script.as_str());
        if script_path.is_file() {
            run_command(script_path, script_name);
        } else {
            eprintln!("Error: Script '{}' not found", script_name);
        }
    } else {
        eprintln!("Error: Script '{}' not found in config", script_name);
    }
}

fn load_config(config_path: String) -> Value {
    let file = File::open(config_path).expect("Error: Unable to open config file");
    let config_str = std::io::read_to_string(file).expect("Error: Unable to read config file");
    toml::from_str(&config_str).expect("Error: Invalid config file format")
}

fn run_command(script_path: &Path, script_name: String) {
    let output = Command::new("cargo")
        .arg("run")
        .arg("--bin")
        .arg(script_name)
        .arg("--")
        .arg(script_path)
        .output()
        .expect("Error: Failed to run script");
    if output.status.success() {
        println!("Script '{}' executed successfully", script_name);
    } else {
        eprintln!("Error: Script '{}' failed with status {}", script_name, output.status.code().unwrap_or(0));
    }
}
