use zenoh::prelude::*;

#[tokio::main]
async fn main() {
    // Create a Zenoh session
    let (z, _, _) = zenoh::open_default().await.unwrap();

    // Define the path and the value to be published
    let path = "/example/path";
    let value = "Hello, World!".to_string();

    // Create a publisher
    let publisher = z
        .declare_publisher(path, zenoh::config::PublisherConfig::default())
        .unwrap();

    // Create a subscriber
    let subscriber = z
        .declare_subscriber(path, zenoh::config::SubscriberConfig::default())
        .unwrap();

    // Publish the value
    publisher
        .publish(value.clone(), zenoh::config::PublishConfig::default())
        .unwrap();

    // Consume the value
    let value = subscriber
        .next_value(&mut zenoh::config::ConsumeConfig::default())
        .await
        .unwrap();

    assert_eq!(value, value);

    // Close the session
    z.close().unwrap();
}
