pub struct Queue<T: IdentifyLookup<Self::AccountId>> {
    queue: StorageMap<u32, Option<Message>, u32>,
}

impl<T: IdentifyLookup<Self::AccountId>> Queue<T> {
    pub fn new() -> Self {
        Self { queue: StorageMap::new() }
    }

    pub fn push_message(&mut self, message: Message) {
        let id = self.queue.insert(message.id, Some(message));
        assert!(id == message.id);
    }

    pub fn pop_message(&mut self) -> Option<Message> {
        let (id, message) = self.queue.first().unwrap();
        self.queue.remove(id);
        message
    }

    pub fn get_message(&self, id: u32) -> Option<&Message> {
        self.queue.get(&id)
    }
}

