struct MyHandler;

impl Handler for MyHandler {
    async fn handle(&self, ctx: Context, req: VercelRequest) -> Result<String, String> {
        let request = req.into_http_request();
        let response = request
            .into_response(StatusCode::Ok, "Hello, world!")
            .await?;
        Ok(response.to_string())
    }
