use std::arch::x86_64::_mm_crc32;
use std::arch::x86_64::_mm_setzero_64;
use std::arch::x86_64::_mm_set1_epi32;
use std::arch::x86_64::CpuFeature;
use std::arch::x86_64::CpuFlags;
use std::arch::x86_64::CpuId;
use crc32c;

pub fn crc32c_safe(data: &[u8], initial_value: u32) -> u32 {
    if crc32c::is_supported() {
        let mut crc = initial_value;
        for byte in data {
            crc = _mm_crc32_u8(crc, *byte);
        }
        crc
    } else {
        let mut crc = initial_value;
        for byte in data {
            crc = crc32c::crc32c(crc, *byte as u32);
        }
        crc
    }
}

fn main() {
    let data = b"Hello, World!";
    let initial_value = 0;
    let crc = crc32c_safe(data, initial_value);
    println!("CRC32C: {}", crc);
}
