use byteorder::{ByteOrder, LittleEndian};
use log::{info, error};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let port = "COM3"; // Replace with your serial port
    let baud_rate = 9600;
    let parity = serialport::Parity::None;
    let stop_bits = serialport::StopBits::One;
    let data_bits = serialport::Bits::Eight;

    let settings = SerialPortSettings {
        baud_rate,
        parity,
        stop_bits,
        data_bits,
        ..Default::default()
    };

    let port = serialport::open(port, &settings)?;
    info!("Serial port opened");

    let data = b"Hello, world!";
    let data_len = data.len() as u16;
    let mut buffer = [0u8; 2];

    LittleEndian::write_u16(&mut buffer, data_len);
    port.write_all(&buffer[..])?;

    port.write_all(data)?;

    let mut response = [0u8; 1024];
    let len = port.read(&mut response[..])?;
    info!("Received: {}", String::from_utf8_lossy(&response[..len]));

    Ok(())
}
```

