use serde::{Serialize, Serializer};
use regex::Regex;
use std::fmt;

#[derive(Debug, PartialEq)]
struct PlainText {
    value: String,
}

impl PlainText {
    fn new(value: String) -> Result<Self, &'static str> {
        if !self::validate(value.as_str()) {
            Err("Invalid plain text")
        } else {
            Ok(PlainText { value })
        }
    }

    fn validate(input: &str) -> bool {
        let pattern = regex::Regex::new("[^a-zA-Z0-9\\s\\.,!?\\-]").unwrap();
        !pattern.is_match(input)
    }
}

impl Serialize for PlainText {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let value = self.value.clone();
        let pattern = regex::Regex::new("[^a-zA-Z0-9\\s\\.,!?\\-]").unwrap();
        let cleaned_value = pattern.replace_all(&value, "");
        serializer.serialize_str(&cleaned_value)
    }
}

impl fmt::Display for PlainText {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", self.value)
    }
}
```

This code defines a custom `PlainText` struct that holds a string value. It provides a `new` method for creating a new `PlainText` instance, which validates the input string against a regular expression. The `Serialize` implementation uses the `serde` crate to serialize the `PlainText` instance to a string, but with some restrictions on allowed characters. The `Display` implementation allows the `PlainText` instance to be formatted as a string.

