use std::collections::HashMap;

struct Node {
    id: i32,
    children: Vec<i32>,
}

struct Tree {
    nodes: Vec<Node>,
    node_map: HashMap<i32, usize>,
}

impl Tree {
    fn new() -> Self {
        Tree {
            nodes: Vec::new(),
            node_map: HashMap::new(),
        }
    }

    fn add_node(&mut self, id: i32, children: Vec<i32>) {
        let node = Node {
            id,
            children,
        };
        self.nodes.push(node);
        self.node_map.insert(id, self.nodes.len() - 1);
    }

    fn get_node(&self, id: i32) -> Option<&Node> {
        self.node_map.get(&id).map(|index| &self.nodes[*index])
    }

    fn get_child_nodes(&self, id: i32) -> Option<&Vec<i32>> {
        self.get_node(id).map(|node| &node.children)
    }
}

fn main() {
    let mut tree = Tree::new();
    tree.add_node(1, vec![]);
    tree.add_node(2, vec![1]);
    tree.add_node(3, vec![1]);
    tree.add_node(4, vec![2, 3]);

    assert_eq!(tree.get_node(1).unwrap().children.len(), 0);
    assert_eq!(tree.get_child_nodes(1).unwrap().len(), 2);
    assert_eq!(tree.get_child_nodes(2).unwrap().len(), 1);
}
