use bitvec::prelude::*;

pub struct BitReader {
    buffer: BitVec,
    position: usize,
}

impl BitReader {
    pub fn new(buffer: &[u8]) -> Self {
        let mut buffer = BitVec::alloc(buffer.len() * 8);
        buffer.copy_from_slice(buffer);
        BitReader { buffer, position: 0 }
    }

    pub fn read(&mut self, count: u8) -> u32 {
        let mut result = 0;
        for _ in 0..count {
            if self.position >= self.buffer.len() * 8 {
                panic!("End of buffer reached");
            }
            result = (result << 1) | self.buffer[self.position];
            self.position += 1;
        }
        result
    }
}

fn main() {
    let buffer = &[0b10101010, 0b11001100];
    let mut reader = BitReader::new(buffer);
    println!("{:b}", reader.read(8)); // prints 11010110
    println!("{:b}", reader.read(8)); // prints 11100000
}
```

This code uses the `bitvec` crate to create a BitVec, which is an array of bits. It then implements a BitReader struct that reads individual bits from this BitVec, supporting arbitrary bit counts. The position of the reader is tracked, and the code panics if the end of the buffer is reached. 

