use cbc_mode::{Cbc, CbcMode};
use aes::Aes256;
use block_modes::{BlockMode, Cbc};
use padding::Pkcs7;
use rand::Rng;
use hex;

fn cbc_encrypt(plain_text: &[u8], key: &[u8], iv: &[u8]) -> Vec<u8> {
    let cipher = Aes256::new(key);
    let mut rng = rand::thread_rng();
    let mut iv = iv.to_vec();

    if iv.len() != 16 {
        panic!("Initialization vector must be 16 bytes long");
    }

    let mut encrypted_text = vec![];
    for chunk in plain_text.chunks(16) {
        let mut padded_chunk = Pkcs7::new(16).pad(chunk);
        let encrypted_chunk = cipher.encrypt_block(&mut padded_chunk);
        encrypted_text.extend_from_slice(&iv);
        encrypted_text.extend_from_slice(&encrypted_chunk);
        rng.fill_bytes(&mut iv);
    }

    encrypted_text
}

fn cbc_decrypt(encrypted_text: &[u8], key: &[u8], iv: &[u8]) -> Vec<u8> {
    let cipher = Aes256::new(key);
    let mut rng = rand::thread_rng();
    let mut iv = iv.to_vec();

    if iv.len() != 16 {
        panic!("Initialization vector must be 16 bytes long");
    }

    let mut decrypted_text = vec![];
    for chunk in encrypted_text.chunks(16) {
        let encrypted_chunk = chunk[..16].to_vec();
        let mut decrypted_chunk = cipher.decrypt_block(&encrypted_chunk);
        let padded_chunk = Pkcs7::new(16).unpad(&mut decrypted_chunk);
        decrypted_text.extend_from_slice(&padded_chunk);
        rng.fill_bytes(&mut iv);
    }

    decrypted_text
}

fn main() {
    let key = b"secret key";
    let iv = b"initialization vector";
    let plain_text = b"This is a secret message";

    let encrypted_text = cbc_encrypt(plain_text, key, iv);
    println!("Encrypted text: {}", hex::encode(&encrypted_text));

    let decrypted_text = cbc_decrypt(&encrypted_text, key, iv);
    println!("Decrypted text: {}", String::from_utf8(decrypted_text).unwrap());
}
