        let cache = Cache::new(CacheOptions::default().ttl(Duration::days(7)))?;
        Ok(CacheStore { cache })
    }

    async fn get(&self, key: &str) -> Result<Option<CacheEntry>, deno_cache::Error> {
        let value = self.cache.get(key).await?;
        if value.is_none() {
            return Ok(None);
        }
        let value = value.unwrap();
        let expires_at = Utc::now() + Duration::days(7);
        let cache_entry = CacheEntry {
            value: serde_json::to_string(&value).unwrap(),
            expires_at,
        };
        Ok(Some(cache_entry))
    }

