```rust
use std::collections::HashMap;
use std::collections::HashSet;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use parking_lot::RwLock;

struct LRUCache<T> {
    size: usize,
    time_to_live: Duration,
    cache: HashMap<T, (Instant, RwLock<()>)>,
    keys: Arc<Mutex<HashSet<T>>>,
}

impl<T> LRUCache<T> {
    fn new(size: usize, time_to_live: Duration) -> Self {
        LRUCache {
            size,
            time_to_live,
            cache: HashMap::new(),
            keys: Arc::new(Mutex::new(HashSet::new())),
        }
    }

    fn get(&self, key: T) -> Option<(T, Instant)> {
        if let Some((instant, _)) = self.cache.get(&key) {
            let key = *key;
            let keys = self.keys.lock().unwrap();
            keys.remove(&key);
            keys.insert(key);
            Some((key, *instant))
        } else {
            None
        }
    }

    fn set(&mut self, key: T, value: Instant) {
        let keys = self.keys.lock().unwrap();
        if keys.contains(&key) {
            keys.remove(&key);
        }
        if self.cache.len() >= self.size {
            let oldest_key = self.cache
                .iter()
                .filter(|(k, _)| value.saturating_duration_since(k.1).abs() >= self.time_to_live)
                .map(|(k, _)| k)
                .min()
                .unwrap();
            self.cache.remove(oldest_key);
            keys.remove(oldest_key);
        }
        self.cache.insert(key, (value, RwLock::new(())));
        keys.insert(key);
    }

    fn delete(&mut self, key: T) {
        let keys = self.keys.lock().unwrap();
        if keys.contains(&key) {
            keys.remove(&key);
            self.cache.remove(&key);
        }
    }
}
