#[proc_macro_attribute]
pub fn panic_free(_args: TokenStream, item: TokenStream) -> TokenStream {
    // Parse the item into a syn structure
    let item = syn::parse_macro_input!(item as syn::ItemFn);

    // Check if the function has a panic handler
    if item.sig.unsafe_token.is_some() {
        return item.to_token_stream();
    }

    // Check if the function contains any potential panic paths
    if check_panic_paths(&item) {
        return item.to_token_stream();
    }

    // If no panic paths are found, add a panic handler to the function
    let item = add_panic_handler(item);

    // Return the modified item as a TokenStream
    item.to_token_stream()
