// A wrapper around a u32 to represent an EAX register value.
#[derive(Copy, Clone, Debug)]
struct Eax(u32);

// A wrapper around a u32 to represent an EBX register value.
#[derive(Copy, Clone, Debug)]
struct Ebx(u32);

// A wrapper around a u32 to represent an ECX register value.
#[derive(Copy, Clone, Debug)]
struct Ecx(u32);

// A wrapper around a u32 to represent an EDX register value.
#[derive(Copy, Clone, Debug)]
struct Edx(u32);

// A wrapper around a u32 to represent a CPUID leaf value.
#[derive(Copy, Clone, Debug)]
struct Leaf(u32);

// A CPUID result.
#[derive(Copy, Clone, Debug)]
struct CpuIdResult {
    eax: Eax,
    ebx: Ebx,
    ecx: Ecx,
    edx: Edx,
}

impl CpuIdResult {
    // Execute the CPUID instruction and return the result.
    fn execute(leaf: Leaf) -> CpuIdResult {
        // Simulate the CPUID instruction. This is a very simplified
        // version and will not work on real hardware.
        let eax = (leaf.0 >> 16) & 0xFF;
        let ebx = (leaf.0 >> 8) & 0xFF;
        let ecx = leaf.0 & 0xFF;
        let edx = (leaf.0 << 8) & 0xFF00;

        CpuIdResult {
            eax: Eax(eax),
            ebx: Ebx(ebx),
            ecx: Ecx(ecx),
            edx: Edx(edx),
        }
    }
}

fn main() {
    let leaf = Leaf(0x1);
    let result = CpuIdResult::execute(leaf);

    println!("CPUID leaf 0x{:X} result:", leaf.0);
    println!("EAX: 0x{:X}", result.eax.0);
    println!("EBX: 0x{:X}", result.ebx.0);
    println!("ECX: 0x{:X}", result.ecx.0);
    println!("EDX: 0x{:X}", result.edx.0);
}
