// Define a struct to hold the disposable email providers
struct DisposableEmailProviders {
    providers: HashSet<String>,
}

impl DisposableEmailProviders {
    // Load the disposable email providers from a JSON file
    fn load_providers() -> Self {
        let url = "https://raw.githubusercontent.com/dontspendyourcash/disposable-email-list/master/disposable_email_list.json";
        let response = get(url).unwrap();
        let json = response.text().unwrap();
        let providers: HashSet<String> = from_str(&json).unwrap();
        DisposableEmailProviders { providers }
    }

    // Check if an email address is disposable
    fn is_disposable(&self, email: &str) -> bool {
        let pattern = self.providers.iter().map(|provider| format!("@{}", provider)).collect::<Vec<String>>().join("|");
        let re = Regex::new(&pattern).unwrap();
        re.is_match(email)
    }
}

fn main() {
    let providers = DisposableEmailProviders::load_providers();
    let email = "temporary@example.com";
    if providers.is_disposable(email) {
        println!("{} is a disposable email address", email);
    } else {
        println!("{} is not a disposable email address", email);
    }
}
