// Define a global static to keep track of the total heap size
static TOTAL_HEAP_SIZE: AtomicUsize = AtomicUsize::new(0);
static ONCE: Once = Once::new();

// Define a trait to measure the total heap size
trait HeapSize {
    fn heap_size(&self) -> usize;
}

// Define a struct to measure the heap size
struct HeapSizeMeasurer {
    _marker: PhantomData<*const ()>,
}

impl HeapSizeMeasurer {
    fn new() -> Self {
        Self {
            _marker: PhantomData,
        }
    }
}

impl Drop for HeapSizeMeasurer {
    fn drop(&mut self) {
        let size = TOTAL_HEAP_SIZE.load(Ordering::SeqCst);
        TOTAL_HEAP_SIZE.store(size + mem::size_of::<Self>(), Ordering::SeqCst);
    }
}

impl HeapSize for HeapSizeMeasurer {
    fn heap_size(&self) -> usize {
        TOTAL_HEAP_SIZE.load(Ordering::SeqCst)
    }
}

// Define a custom global allocator to measure the heap size
struct CustomAlloc;

impl GlobalAlloc for CustomAlloc {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let measurer = HeapSizeMeasurer::new();
        let ptr = std::alloc::alloc(layout);
        measurer;
        ptr
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        std::alloc::dealloc(ptr, layout);
    }
}

// Initialize the global allocator
#[global_allocator]
static GLOBAL_ALLOCATOR: CustomAlloc = CustomAlloc;

fn main() {
    ONCE.call_once(|| {
        // Initialize the total heap size to 0
        TOTAL_HEAP_SIZE.store(0, Ordering::SeqCst);
    });

    let measurer = HeapSizeMeasurer::new();
    let _ = String::from("hello");

    println!("Total heap size: {}", measurer.heap_size());
}
