use libsodium_sys::crypto;
use base64;
use bincode;

fn main() {
    // Generate a secret key
    let mut key = [0u8; 32];
    crypto::randombytes(&mut key);

    // Encrypt a message
    let message = "Hello, World!";
    let encrypted_message = encrypt(&key, message);

    // Decrypt the message
    let decrypted_message = decrypt(&key, &encrypted_message);

    println!("Original message: {}", message);
    println!("Encrypted message: {}", base64::encode(&encrypted_message));
    println!("Decrypted message: {}", decrypted_message);
}

fn encrypt(key: &[u8; 32], message: &str) -> Vec<u8> {
    let message_bytes = message.as_bytes();
    let encrypted_message = crypto::secretbox_easy(&message_bytes, &key, &[]);
    encrypted_message.to_vec()
}

fn decrypt(key: &[u8; 32], encrypted_message: &[u8]) -> String {
    let decrypted_message = crypto::secretbox_open_easy(&encrypted_message, &key, &[]);
    String::from_utf8(decrypted_message).unwrap()
}
