// Define a trait for serializing Rust structs to JSON
trait SerializeToJson {
    fn to_json(&self) -> String;
}

// Implement the trait for any type that implements Serialize
trait Serialize: serde::Serialize {}

// Implement SerializeToJson for any type that implements Serialize
impl<T: Serialize> SerializeToJson for T {
    fn to_json(&self) -> String {
        serde_json::to_string(self).unwrap()
    }
}

// Define a derive macro to automatically derive SerializeToJson for any struct with public fields
#[proc_macro_derive(SerializeToJson)]
pub fn derive_serialize_to_json(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let fields: Vec<syn::Field> = input.data.struct_data.fields.iter().filter(|f| f.vis.is_public()).collect();
    if fields.is_empty() {
        return syn::Error::new(input.data.struct_data.ident.span(), "struct must have at least one public field").to_compile_error();
    }

    let name = input.data.struct_data.ident;
    let fields: String = fields
        .into_iter()
        .map(|field| format!("{:?} {:?}", field.ident, field.ty))
        .collect::<Vec<_>>()
        .join(", ");

    let json = format!("{} {{\n    {},\n}}", name, fields);
    quote::quote! {
        impl SerializeToJson for #name {
            fn to_json(&self) -> String {
                #json
            }
        }
    }
    .into()
}
