#[derive(Debug)]
struct Stopwatch {
    start_time: Instant,
    elapsed_time: u128,
}

impl Stopwatch {
    pub fn new() -> Self {
        Self {
            start_time: Instant::now(),
            elapsed_time: 0,
        }
    }

    pub fn start(&mut self) {
        self.start_time = Instant::now();
    }

    pub fn stop(&mut self) {
        self.elapsed_time += self.start_time.elapsed().as_nanos() as u128;
    }

    pub fn elapsed(&self) -> u128 {
        self.elapsed_time + self.start_time.elapsed().as_nanos() as u128
    }

    pub fn elapsed_human_readable(&self) -> String {
        time::format_description![format_description!(
            "[hour]:minute:second",
            #[offset(0)]
            #[style("pad")]
            #[item(FormatItemKind::Minute, 0)]
            #[item(FormatItemKind::Separator, ":")]
            #[item(FormatItemKind::Second, 0)]
        )]
        .format(self.elapsed())
        .unwrap()
    }
}

fn main() {
    let mut stopwatch = Stopwatch::new();
    stopwatch.start();
    // Do some work...
    std::thread::sleep(std::time::Duration::from_millis(1000));
    stopwatch.stop();
    println!("Elapsed time: {}", stopwatch.elapsed_human_readable());
}
