enum Message {
    Increment,
    Decrement,
    Reset,
}

impl Application for Counter {
    type Message = Message;
    type Flags = ();

    fn new(_flags: ()) -> (Counter, Command<Self::Message>) {
        (Counter::default(), Command::none())
    }

