        String::from("Counter App")
    }

    fn update(&mut self, message: Self::Message) {
        match message {
            Message::Increment => self.count += 1,
            Message::Decrement => {
                if self.count > 0 {
                    self.count -= 1;
                }
            }
            Message::Reset => self.count = 0,
        }
    }

