use regex::{Regex, RegexBuilder};
use walkdir::WalkDir;
use std::fs;
use std::path::{Path, PathBuf};
use std::error::Error;
use clap::{App, Arg};

fn main() -> Result<(), Box<dyn Error>> {
    let matches = App::new("file_bundler")
        .version("1.0")
        .author("Your Name")
        .about("A regex-based file bundler")
        .arg(Arg::with_name("pattern")
            .help("Regex pattern to match module paths")
            .required(true)
            .index(1))
        .arg(Arg::with_name("output")
            .help("Output directory for bundled files")
            .required(true)
            .index(2))
        .get_matches();

    let pattern = matches.value_of("pattern").unwrap();
    let output_dir = matches.value_of("output").unwrap();

    let re = RegexBuilder::new(pattern)
        .case_insensitive(true)
        .build()?;

    for entry in WalkDir::new(".")
        .into_iter()
        .filter_map(|e| e.ok())
    {
        let path = entry.path();
        if path.is_dir() {
            continue;
        }

        let file_name = path.file_name().unwrap();
        let file_name_str = file_name.to_string_lossy();
        if re.is_match(&file_name_str) {
            println!("Moving {} to {}", path.display(), output_dir);
            fs::rename(path, PathBuf::from(output_dir).join(file_name))?;
        }
    }

    Ok(())
}
```

This code uses the `regex` crate for regex matching, `walkdir` crate for walking the directory tree, and `clap` crate for parsing command-line arguments. It takes a regex pattern and an output directory as command-line arguments, and moves files matching the pattern to the output directory.

To use this code, you'll need to add the following lines to your `Cargo.toml` file:

```toml
