const FRAME_LIMITING_ENABLED: bool = true;

// Data for frame pacing and limiting
struct FramePacing {
    target_fps: f32,
    variance: f32,
    last_frame_time: f32,
    last_frame_timestamp: f32,
}

impl Default for FramePacing {
    fn default() -> Self {
        Self {
            target_fps: FPS_TARGET,
            variance: FPS_VARIANCE,
            last_frame_time: 0.0,
            last_frame_timestamp: 0.0,
        }
    }
}

// System for updating the frame pacing and limiting data
fn update_frame_pacing(
    mut commands: Commands,
    time: Res<Time>,
    frame_pacing: ResMut<FramePacing>,
    window: Res<Window>,
    mut frame_limiter: ResMut<FrameLimiter>,
) {
    let current_time = time.seconds_since_startup() as f32;
    let current_fps = 1.0 / (current_time - frame_pacing.last_frame_time);

    // Update last frame time and timestamp
    frame_pacing.last_frame_time = current_time;
    frame_pacing.last_frame_timestamp = current_time;

    // Adjust frame rate to target FPS
    let target_time = 1.0 / FPS_TARGET;
    let adjusted_time = (current_time - frame_pacing.last_frame_time) + target_time;

    // Apply frame limiting if enabled
    if FRAME_LIMITING_ENABLED {
        frame_limiter.set_target_fps(FPS_TARGET);
    }

    // Update last frame time and timestamp
    frame_pacing.last_frame_time = current_time + adjusted_time;
    frame_pacing.last_frame_timestamp = current_time + adjusted_time;
