const XZ_LEVEL: i32 = 6;

async fn compress(input_path: &Path, output_path: &Path) -> Result<()> {
    let input = fs::File::open(input_path).context("Failed to open input file")?;
    let output = fs::File::create(output_path).context("Failed to create output file")?;

    let mut input_stream = xz2::read::XzDecoder::new(input);
    let mut encoder = XzEncoder::new(output, XZ_LEVEL);

    info!("Compressing file...");
    tokio::io::copy(&mut input_stream, &mut encoder).await?;

    Ok(())
}

async fn decompress(input_path: &Path, output_path: &Path) -> Result<()> {
    let input = fs::File::open(input_path).context("Failed to open input file")?;
    let output = fs::File::create(output_path).context("Failed to create output file")?;

    let mut input_stream = xz2::read::XzDecoder::new(input);
    let mut decoder = ZlibDecoder::new(input_stream);

    info!("Decompressing file...");
    tokio::io::copy(&mut decoder, &mut output).await?;

    Ok(())
}

#[tokio::main]
async fn main() -> Result<()> {
    let input_path = Path::new("input.txt");
    let compressed_path = Path::new("input.txt.xz");
    let decompressed_path = Path::new("input.txt");

    info!("Compressing file...");
    compress(input_path, compressed_path).await?;

    info!("Decompressing file...");
    decompress(compressed_path, decompressed_path).await?;

