use std::alloc::{GlobalAlloc, Layout};
use std::cell::Cell;
use std::marker::PhantomData;
use std::sync::ThreadLocal;

thread_local! {
    static ARENA_ALLOCATOR: Cell<ArenaAllocator> = Cell::new(ArenaAllocator::new());
}

struct ArenaAllocator {
    current_block: *mut u8,
    next_block: *mut u8,
    size: usize,
    _phantom: PhantomData<*mut ()>,
}

impl ArenaAllocator {
    fn new() -> Self {
        Self {
            current_block: std::alloc::alloc(Layout::from_size_align(4096, 4096).unwrap()),
            next_block: std::alloc::alloc(Layout::from_size_align(4096, 4096).unwrap()),
            size: 4096,
            _phantom: PhantomData,
        }
    }

    fn allocate<T>(&self) -> *mut T {
        let layout = Layout::new::<T>();
        let size = layout.size();
        if self.current_block.offset_from(self.next_block) >= self.size {
            self.next_block = std::alloc::alloc(layout);
            self.size = layout.size();
        }
        self.current_block = self.current_block.offset(1);
        self.current_block as *mut T
    }

    fn deallocate(&self) {
        std::alloc::dealloc(self.next_block, Layout::from_size_align(4096, 4096).unwrap());
        self.next_block = self.current_block;
        self.current_block = self.next_block.offset(-1);
    }
}

impl Drop for ArenaAllocator {
    fn drop(&mut self) {
        self.deallocate();
        std::alloc::dealloc(self.next_block, Layout::from_size_align(4096, 4096).unwrap());
    }
}

impl GlobalAlloc for ArenaAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let arena_allocator = ARENA_ALLOCATOR.with(|allocator| allocator.get());
        arena_allocator.allocate::<u8>()
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        let arena_allocator = ARENA_ALLOCATOR.with(|allocator| allocator.get());
        arena_allocator.deallocate();
    }
