type Interner = Arc<Mutex<HashMap<String, usize>>>;

// Define a static instance of the interner
static INTERNER: AtomicUsize = AtomicUsize::new(0);
static mut GLOBAL_INTERNER: Option<Interner> = None;

// Initialize the global interner
fn init_interner() {
    let interner = Arc::new(Mutex::new(HashMap::new()));
    let global_interner = Arc::clone(&interner);
    unsafe {
        GLOBAL_INTERNER = Some(global_interner);
        INTERNER.store(0, Ordering::Relaxed);
    }
}

// Intern a string
fn intern(string: &str) -> usize {
    let global_interner = unsafe { GLOBAL_INTERNER.as_ref().unwrap() };
    let mut interner = global_interner.lock().unwrap();
    let hash = hash(string);
    if let Some(index) = interner.get(&string.to_string()) {
        return *index;
    }
    let index = *INTERNER.fetch_add(1, Ordering::Relaxed);
    interner.insert(string.to_string(), index);
    index
}

