use google_cloud_pubsub::{PubSub, Topic, Subscription};
use tokio::prelude::*;
use serde::{Serialize, Deserialize};
use serde_json::json;
use log::{info, error};
use env_logger::Env;

#[derive(Serialize, Deserialize)]
struct Message {
    id: String,
    content: String,
}

#[tokio::main]
async fn main() {
    env_logger::init_from_env(Env::default().default_filter_or("info"));

    let project_id = std::env::var("GOOGLE_CLOUD_PROJECT").expect("GOOGLE_CLOUD_PROJECT must be set");
    let pubsub = PubSub::new(project_id);

    // Create a topic
    let topic = Topic::create(&pubsub, "my-topic").await.unwrap();
    info!("Topic created: {}", topic.name);

    // Create a subscription
    let subscription = Subscription::create(&pubsub, "my-subscription", topic.name).await.unwrap();
    info!("Subscription created: {}", subscription.name);

    // Publish a message to the topic
    let message = Message {
        id: "1".to_string(),
        content: "Hello, World!".to_string(),
    };
    let json_message = serde_json::to_string(&message).unwrap();
    let topic_path = topic.name.clone();
    let message = pubsub.publish(&topic_path, json_message).await.unwrap();
    info!("Message published: {}", message.message_id);

    // Create a stream to receive messages from the subscription
    let subscription_path = subscription.name.clone();
    let stream = pubsub.pull(&subscription_path).await.unwrap();
    info!("Streaming messages from subscription");

    while let Some(result) = stream.next().await {
        match result {
            Ok(message) => {
                let data = message.message.data;
                let json_message = String::from_utf8(data).unwrap();
                let message: Message = serde_json::from_str(&json_message).unwrap();
                info!("Received message: {:?}", message);
            }
            Err(e) => {
                error!("Error pulling messages: {}", e);
            }
        }
    }

    // Clean up
    topic.delete(&pubsub).await.unwrap();
    subscription.delete(&pubsub).await.unwrap();
}
