#[service]
impl Service for Microservice {
    async fn handle_request(&self, req: Request) -> Response {
        // Handle the request
        let result = format!("Received message: {}", req.message);
        Response { result }
    }
}

// Generate the client and server code
generate! {
    // Generate the client
    generate_client!(Client, Microservice);

    // Generate the server
    generate_server!(Server, Microservice);
}

// Define the main function
#[tokio::main]
async fn main() {
    // Create a new server
    let server = Server::new("0.0.0.0:8080");

    // Start the server
    server.start().await;

    // Create a new client
    let client = Client::new("http://localhost:8080");

    // Send a request to the server
    let (tx, rx) = mpsc::channel(1);
    let req = Request { message: "Hello, world!".to_string() };
    let client_clone = client.clone();
    tokio::spawn(async move {
        let res = client_clone.call(req).await;
        tx.send(res).await.unwrap();
    });

    // Receive the response from the server
    let res = rx.recv().await.unwrap();

    // Print the response
    println!("{:?}", res);
}
