impl BinaryTree {
    pub fn new() -> Self {
        BinaryTree { root: None }
    }

    // Insert a new node into the tree
    pub fn insert(&mut self, val: i32) {
        let mut root = self.root.get_or_insert(Box::new(TreeNode::new(0)));
        self.insert_recursive(root, val);
    }

