    fn insert_recursive(&mut self, node: &mut Box<TreeNode>, val: i32) {
        if val < node.val {
            if node.left.is_none() {
                node.left = Some(Box::new(TreeNode::new(val)));
            } else {
                self.insert_recursive(&mut node.left.as_mut().unwrap(), val);
            }
        } else {
            if node.right.is_none() {
                node.right = Some(Box::new(TreeNode::new(val)));
