use nalgebra::{Point2, Vector2};
use num_traits::Float;

struct AABB {
    position: Point2<Float>,
    dimensions: Vector2<Float>,
}

impl AABB {
    fn new(position: Point2<Float>, dimensions: Vector2<Float>) -> Self {
        AABB {
            position,
            dimensions,
        }
    }

    fn contains(&self, point: Point2<Float>) -> bool {
        let x = self.position.x;
        let y = self.position.y;
        let w = self.dimensions.x;
        let h = self.dimensions.y;
        point.x >= x && point.x <= x + w && point.y >= y && point.y <= y + h
    }

    fn collides(&self, other: &AABB) -> bool {
        let x_overlap = (self.position.x - other.position.x).abs() <= (self.dimensions.x + other.dimensions.x) / 2.0;
        let y_overlap = (self.position.y - other.position.y).abs() <= (self.dimensions.y + other.dimensions.y) / 2.0;
        x_overlap && y_overlap
    }
}

fn main() {
    let aabb1 = AABB::new(Point2::new(0.0, 0.0), Vector2::new(10.0, 10.0));
    let aabb2 = AABB::new(Point2::new(5.0, 5.0), Vector2::new(5.0, 5.0));

    println!("Does AABB1 contain point (1, 1)? {}", aabb1.contains(Point2::new(1.0, 1.0)));
    println!("Do AABB1 and AABB2 collide? {}", aabb1.collides(&aabb2));
}
