// Define the struct for a free block in the list
struct FreeBlock {
    size: usize,
    next: Option<Box<FreeBlock>>,
}

// Define the allocator struct
struct NoStdAllocator {
    free_list: Option<Box<FreeBlock>>,
}

impl NoStdAllocator {
    // Initialize the allocator with a free list
    fn init(&mut self, size: usize) {
        self.free_list = Some(Box::new(FreeBlock {
            size,
            next: None,
        }));
    }

    // Allocate a block of memory
    fn allocate(&mut self, size: usize) -> *mut u8 {
        let mut current = self.free_list.as_mut();
        while let Some(block) = current {
            if block.size >= size {
                let new_size = block.size - size;
                let new_block = Box::new(FreeBlock {
                    size: new_size,
                    next: block.next.take(),
                });
                block.size = size;
                block.next = Some(new_block);
                current = Some(block);
                return Box::into_raw(Box::new([0; size]));
            }
            current = block.next.as_mut();
        }
        // If no free block is found, return None
        None
    }

    // Deallocate a block of memory
    fn deallocate(&mut self, ptr: *mut u8, size: usize) {
        let mut current = self.free_list.as_mut();
        let mut prev = None;
        while let Some(block) = current {
            if block.size == size {
                let new_block = Box::new(FreeBlock {
                    size: block.size,
                    next: block.next.take(),
                });
                if let Some(prev_block) = prev {
                    prev_block.next = Some(new_block);
                } else {
                    self.free_list = Some(new_block);
                }
                return;
            }
            prev = Some(block);
            current = block.next.as_mut();
        }
        // If no matching free block is found, add the deallocated block to the free list
        let block = Box::new(FreeBlock {
            size,
            next: self.free_list.take(),
        });
        self.free_list = Some(block);
    }
}

